import{_ as o,o as a,c as i,a2 as r}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"期权交易入门","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/options/options-getting-started.md","filePath":"zh-CN/derivatives/options/options-getting-started.md"}'),e={name:"derivatives/options/options-getting-started.md"};function n(s,t,l,p,h,d){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="期权交易入门" tabindex="-1">期权交易入门 <a class="header-anchor" href="#期权交易入门" aria-label="Permalink to &quot;期权交易入门&quot;">​</a></h1><p>在本教程结束时，你将完成第一笔看涨期权的买入，并通过卖出平仓，走完一个完整的期权交易周期。</p><p>完成这个教程大约需要 <strong>15 分钟</strong>，需要在美股交易时间内操作（美东时间周一至周五 09:30–16:00）。</p><h2 id="开始前的准备" tabindex="-1">开始前的准备 <a class="header-anchor" href="#开始前的准备" aria-label="Permalink to &quot;开始前的准备&quot;">​</a></h2><p>确认以下两项：</p><ul><li>账户已开通<strong>一级期权权限</strong>（可交易 Long Call 和 Long Put）</li><li>账户中有足够美元余额（至少 200–500 USD，用于支付权利金）</li></ul><p>如果尚未开通期权权限，请先完成<a href="/wiki/derivatives/options/enable-options">开通期权交易</a>。</p><blockquote><p>本教程只涉及<strong>买入看涨期权（Long Call）</strong>。最大亏损限于支付的权利金，无其他额外风险。</p></blockquote><h2 id="第一步-找到目标股票" tabindex="-1">第一步：找到目标股票 <a class="header-anchor" href="#第一步-找到目标股票" aria-label="Permalink to &quot;第一步：找到目标股票&quot;">​</a></h2><p>点击 App 搜索图标，输入 <strong>AAPL</strong>（苹果公司）。</p><p>进入 AAPL 股票详情页，查看顶部显示的<strong>当前股价</strong>。记下这个价格，接下来选择行权价时会用到。</p><blockquote><p>本教程用 AAPL 举例——它是流动性最好的美股期权标的之一，买卖价差较小，适合入门。你也可以换成任何你熟悉的美股。</p></blockquote><h2 id="第二步-进入期权链" tabindex="-1">第二步：进入期权链 <a class="header-anchor" href="#第二步-进入期权链" aria-label="Permalink to &quot;第二步：进入期权链&quot;">​</a></h2><p>在 AAPL 详情页顶部 Tab 栏中，点击**「期权链」**。</p><p>你会进入期权链页面，顶部横向排列着不同的到期日。</p><h2 id="第三步-选择到期日" tabindex="-1">第三步：选择到期日 <a class="header-anchor" href="#第三步-选择到期日" aria-label="Permalink to &quot;第三步：选择到期日&quot;">​</a></h2><p>在到期日列表中，选择一个<strong>距今 2–4 周</strong>的到期日。</p><p>你会看到有些标记了「W」，代表周期权；没有标记的是月期权。选一个<strong>月期权</strong>（无「W」标记）——它的流动性更好，买卖价差更小。</p><p>选好到期日后，合约列表会更新。</p><h2 id="第四步-选择行权价" tabindex="-1">第四步：选择行权价 <a class="header-anchor" href="#第四步-选择行权价" aria-label="Permalink to &quot;第四步：选择行权价&quot;">​</a></h2><p>确认筛选栏方向为**「Call」**（看涨）。</p><p>合约列表以当前股价为中轴排列，<strong>蓝色背景的行</strong>是价内期权（行权价低于当前股价），<strong>白色背景的行</strong>是价外期权。</p><p>找到<strong>刚好高于当前股价的第一或第二行</strong>（轻度价外 Call），点击进入合约详情页。</p><blockquote><p>第一次操作选轻度价外即可。行权价与权利金的取舍关系，见<a href="/wiki/derivatives/options/options-buyer">期权买方</a>。</p></blockquote><h2 id="第五步-买入-1-张看涨期权" tabindex="-1">第五步：买入 1 张看涨期权 <a class="header-anchor" href="#第五步-买入-1-张看涨期权" aria-label="Permalink to &quot;第五步：买入 1 张看涨期权&quot;">​</a></h2><p>在合约详情页：</p><ol><li>查看右下角**「买入」<strong>按钮旁显示的</strong>买价（Ask）**——这是你需要支付的权利金单价</li><li>记住：1 张合约 = 100 股，<strong>总权利金 = 权利金单价 × 100</strong></li><li>点击**「买入」**</li></ol><p>在下单面板中：</p><ol><li>确认方向：<strong>买入（Buy to Open）</strong></li><li>数量：填 <strong>1</strong>（张）</li><li>委托类型：选<strong>限价</strong>，价格填当前 Ask 价（或略高 1–2 分以确保成交）</li><li>确认预估总金额（即你需要支付的权利金）</li><li>点击提交，再点确认</li></ol><p>你会看到提示「订单已提交」。</p><h2 id="第六步-确认持仓" tabindex="-1">第六步：确认持仓 <a class="header-anchor" href="#第六步-确认持仓" aria-label="Permalink to &quot;第六步：确认持仓&quot;">​</a></h2><p>进入<strong>资产 → 持仓</strong>，切换到**「期权」**标签。</p><p>你会看到刚才买入的期权合约，显示：</p><ul><li>持仓数量：1 张（正数 = 多头 = 买方权利）</li><li>权利金成本：你支付的总金额</li><li>当前市值：随标的股价实时变化</li></ul><p><strong>恭喜！你已完成第一笔期权买入。</strong></p><h2 id="第七步-卖出平仓-关闭仓位" tabindex="-1">第七步：卖出平仓（关闭仓位） <a class="header-anchor" href="#第七步-卖出平仓-关闭仓位" aria-label="Permalink to &quot;第七步：卖出平仓（关闭仓位）&quot;">​</a></h2><p>持有期权时，有三种结果：</p><p><strong>主动平仓（推荐）</strong>：在到期前任何时间，在持仓页面点击该期权合约，选**「卖出」**，即可按当前市价卖出平仓，获得当前市值的权利金收入，结束这笔交易。</p><p><strong>到期价内自动行权</strong>：若到期时股价高于行权价，期权自动行权，你将以行权价买入 100 股 AAPL 正股（需账户有足够美元余额）。</p><p><strong>到期价外自动作废</strong>：若到期时股价低于行权价，期权自动作废，损失全部权利金——这也是你的最大亏损上限。</p><hr><p>走完这个流程，你已经体验了期权的完整周期：选标的 → 读期权链 → 买入 → 持仓 → 平仓。</p><ul><li>深入理解盈亏结构：<a href="/wiki/derivatives/options/options-buyer">期权买方</a></li><li>看期权链数据字段含义：<a href="/wiki/derivatives/options/options-chain">期权链</a></li><li>使用计算器估算到期盈亏：<a href="/wiki/derivatives/options/options-calculator">期权计算器</a></li></ul>',43)])])}const c=o(e,[["render",n]]);export{u as __pageData,c as default};
